#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k04670Custom {
public:
  __aicore__ inline KernelCa6k04670Custom() {}

  __aicore__ inline void Init(GM_ADDR x, GM_ADDR y, GM_ADDR weight, GM_ADDR bias,
                              GM_ADDR mean, GM_ADDR var,
                              uint32_t totalLength, uint32_t tileLength,
                              uint32_t N, uint32_t C, uint32_t H, uint32_t W,
                              float eps) {
    totalLen_ = totalLength;
    tileLen_ = tileLength;
    N_ = N;
    C_ = C;
    H_ = H;
    W_ = W;
    spatialLen_ = H * W;
    eps_ = eps;

    xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
    yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);
    weightGm_.SetGlobalBuffer((__gm__ float*)weight, C_);
    biasGm_.SetGlobalBuffer((__gm__ float*)bias, C_);
    meanGm_.SetGlobalBuffer((__gm__ float*)mean, C_);
    varGm_.SetGlobalBuffer((__gm__ float*)var, C_);

    pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
    pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
    pipe_.InitBuffer(tmpQueue_, 1, tileLen_ * sizeof(float));
    pipe_.InitBuffer(scaleQueue_, 1, tileLen_ * sizeof(float));
  }

  __aicore__ inline void Process() {
    if (totalLen_ == 0 || tileLen_ == 0) return;

    const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
    const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

    // Grid-stride loop over tiles (each tile is spatialLen_ elements flat)
    const uint32_t strideElems = blockNum * tileLen_;
    uint32_t base = blockIdx * tileLen_;
    if (base >= totalLen_) return;

    // Prefetch first tile
    uint32_t curLen = totalLen_ - base;
    if (curLen > tileLen_) curLen = tileLen_;
    CopyIn(base, curLen);

    while (true) {
      uint32_t nextBase = base + strideElems;
      uint32_t nextLen = 0;
      if (nextBase < totalLen_) {
        nextLen = totalLen_ - nextBase;
        if (nextLen > tileLen_) nextLen = tileLen_;
        CopyIn(nextBase, nextLen);
      }

      Compute(base, curLen);
      CopyOut(base, curLen);

      if (nextLen == 0) break;
      base = nextBase;
      curLen = nextLen;
    }
  }

private:
  __aicore__ inline void CopyIn(uint32_t gmOffset, uint32_t len) {
    AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
    AscendC::DataCopy(xLocal, xGm_[gmOffset], len);
    inQueueX_.EnQue(xLocal);
  }

  __aicore__ inline void Compute(uint32_t gmOffset, uint32_t len) {
    AscendC::LocalTensor<float> xLocal = inQueueX_.DeQue<float>();
    AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
    AscendC::LocalTensor<float> tmp = tmpQueue_.AllocTensor<float>();
    AscendC::LocalTensor<float> scale = scaleQueue_.AllocTensor<float>();

    // For each element, determine channel index c = (offset / spatialLen) % C
    // We'll decompose manually using loop over tiles. But for SIMD, we need to load per-channel mean/var/weight/bias.
    // Since tileLen may be small and contiguous in spatial dimensions,
    // we can process per channel by iterating in blocks of spatialLen.
    // However, to keep simple, we use a scalar loop pattern using vector operations on the entire tile,
    // but we need to replicate per-channel params. That is tricky.
    // Instead, we do a per-element loop in DataCopy simulation. But AscendC does not support per-element loops in vector.
    // We'll compute using repeated vector operations on sub-tiles of size spatialLen.
    // Tile structure: [N, C, H, W] flat. For each element, c = (pos / spatialLen) % C.
    // Since spatialLen may be large, we can process one channel at a time within a tile.
    // We'll iterate over channels that are fully contained in the tile.
    uint32_t startGlobal = gmOffset;
    uint32_t remaining = len;
    uint32_t offset = 0;
    while (remaining > 0) {
      uint32_t globalIdx = startGlobal + offset;
      // if globalIdx >= totalLen_ break.
      uint32_t posInChannel = globalIdx % spatialLen_;
      uint32_t c = (globalIdx / spatialLen_) % C_;
      // We need to process up to spatialLen_ elements from this channel.
      uint32_t avail = spatialLen_ - posInChannel;
      if (avail > remaining) avail = remaining;
      // Load mean, var, weight, bias for channel c (scalars)
      // Since these are scalars, we can broadcast them using vector operations.
      // Using vector broadcast to fill a local tensor.
      // But we only have scalar values in global memory; need to load them.
      // We'll load them via DataCopy of single element (but aligned?).
      // To simplify, we will pre-load all channel params into local memory per block? Not feasible for many channels.
      // Instead, we can use scalar loads inside the vector loop? AscendC does not have scalar loads.
      // As a workaround, we can do the normalization using vector operations with broadcast by first loading the scalar into a local tensor of length avail.
      // We'll use DataCopy for a single float? DataCopy requires address alignment and at least one block? Usually we can copy 1 element with DataCopy(dst, src, 1).
      // But GM to local single element is allowed.
      // We'll load mean, var, weight, bias into local scalars via separate copies.
      // Then use Muls and Adds with vector.

      // Load mean for channel c
      float meanVal = meanGm_.GetValue(c);
      float varVal = varGm_.GetValue(c);
      float weightVal = weightGm_.GetValue(c);
      float biasVal = biasGm_.GetValue(c);
      // Compute invStd = 1 / sqrt(var + eps)
      float invStd = 1.0f / sqrtf(varVal + eps_);

      // Extract sub-tile from xLocal (starting at offset)
      // We need to copy a slice: xLocal[offset:offset+avail] -> tmp
      AscendC::LocalTensor<float> subX = xLocal[offset];
      AscendC::LocalTensor<float> subY = yLocal[offset];
      // Compute: y = (x - mean) * invStd * weight + bias
      AscendC::Subs(tmp, subX, meanVal, avail);
      AscendC::Muls(tmp, tmp, invStd, avail);
      AscendC::Muls(tmp, tmp, weightVal, avail);
      AscendC::Adds(subY, tmp, biasVal, avail);

      offset += avail;
      remaining -= avail;
    }

    tmpQueue_.FreeTensor(tmp);
    scaleQueue_.FreeTensor(scale);
    outQueueY_.EnQue<float>(yLocal);
    inQueueX_.FreeTensor(xLocal);
  }

  __aicore__ inline void CopyOut(uint32_t gmOffset, uint32_t len) {
    AscendC::LocalTensor<float> yLocal = outQueueY_.DeQue<float>();
    AscendC::DataCopy(yGm_[gmOffset], yLocal, len);
    outQueueY_.FreeTensor(yLocal);
  }

private:
  AscendC::TPipe pipe_;
  AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
  AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
  AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;
  AscendC::TQue<AscendC::TPosition::VECCALC, 1> scaleQueue_;

  AscendC::GlobalTensor<float> xGm_;
  AscendC::GlobalTensor<float> yGm_;
  AscendC::GlobalTensor<float> weightGm_;
  AscendC::GlobalTensor<float> biasGm_;
  AscendC::GlobalTensor<float> meanGm_;
  AscendC::GlobalTensor<float> varGm_;

  uint32_t totalLen_ {0};
  uint32_t tileLen_ {0};
  uint32_t N_ {0};
  uint32_t C_ {0};
  uint32_t H_ {0};
  uint32_t W_ {0};
  uint32_t spatialLen_ {0};
  float eps_ {1e-5f};
};

extern "C" __global__ __aicore__ void ca6k04670_custom(GM_ADDR x, GM_ADDR y, GM_ADDR weight, GM_ADDR bias,
                                                        GM_ADDR mean, GM_ADDR var,
                                                        GM_ADDR workspace, GM_ADDR tiling) {
  GET_TILING_DATA(tiling_data, tiling);
  KernelCa6k04670Custom op;
  op.Init(x, y, weight, bias, mean, var,
          tiling_data.totalLength, tiling_data.tileLength,
          tiling_data.N, tiling_data.C, tiling_data.H, tiling_data.W,
          tiling_data.eps);
  op.Process();
}
