import torch
import torch_npu
import custom_ops_lib

_FN = 'ca6k04670_custom'

class ModelNew(torch.nn.Module):
    def __init__(self, num_features: int, affine: bool = True, eps: float = 1e-5, momentum: float = 0.1):
        super().__init__()
        # We need to initialize buffers as in the original SyncBatchNorm.
        # But since the custom op expects weight, bias, running_mean, running_var as inputs,
        # we store them as parameters/buffers.
        self.num_features = num_features
        self.affine = affine
        self.eps = eps
        self.momentum = momentum
        if affine:
            self.weight = torch.nn.Parameter(torch.ones(num_features))
            self.bias = torch.nn.Parameter(torch.zeros(num_features))
        else:
            self.register_parameter('weight', None)
            self.register_parameter('bias', None)
        self.register_buffer('running_mean', torch.zeros(num_features))
        self.register_buffer('running_var', torch.ones(num_features))

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        # In training, normally running_mean/var are updated, but here we use stored values.
        # The custom op expects weight, bias, running_mean, running_var.
        # If affine=False, weight and bias are None, but the operator expects tensors.
        # We handle by substituting ones and zeros.
        if not self.affine:
            w = torch.ones(self.num_features, dtype=x.dtype, device=x.device)
            b = torch.zeros(self.num_features, dtype=x.dtype, device=x.device)
        else:
            w = self.weight
            b = self.bias
        fn = getattr(custom_ops_lib, _FN)
        return fn(x, w, b, self.running_mean, self.running_var, self.eps)
